SELECT DISTINCT chart_version
FROM size_charts
WHERE age_group = 'Teen';

SELECT version_number
FROM size_chart_versions
WHERE status = 'Approved';

SELECT COUNT(*) AS total_notes
FROM size_chart_notes
WHERE chart_id = 0;

SELECT chart_id, MAX(target_age_range_max) AS max_age_range
FROM size_charts
GROUP BY chart_id;

SELECT chart_id, product_line_id
FROM product_associations
WHERE product_line_id = 0;

SELECT note_text
FROM size_chart_notes
WHERE note_type = 'Regional';

SELECT COUNT(DISTINCT chart_id) AS approved_chart_count
FROM size_chart_versions
WHERE status = 'Approved';

SELECT status, COUNT(version_number) AS version_count
FROM size_chart_versions
GROUP BY status;

SELECT chart_id, chart_description
FROM size_charts
WHERE updated_at = (SELECT MAX(updated_at) FROM size_charts);
